import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [72],
    options: {
      chart: {
        height: 350,
        type: 'radialBar',
      },
      plotOptions: {
        radialBar: {
          hollow: {
            margin: 15,
            size: '70%',
            image: '../../assets/images/clock.png',
            imageWidth: 64,
            imageHeight: 64,
            imageClipped: false,
          },
          dataLabels: {
            name: {
              show: false,
              color: '#fff',
            },
            value: {
              show: true,
              color: '#333',
              offsetY: 70,
              fontSize: '22px',
            },
          },
        },
      },
      colors: ['#20E647'],
      fill: {
        type: 'solid',
      },
      stroke: {
        lineCap: 'round',
      },
      labels: ['Time on Task'],
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="radialBar"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart
